ee:message.ee:set-payload:
%dw 2.0 output application/json
var point_metrics = "point_metrics": vars.pointMetricsResult var sleep_sessions = "sleep_sessions": vars.sleepSessionsResult var workouts = "workouts": vars.workOutsResult groupBy ((item, index) -> item.id) pluck ((rows,workoutId) ->{ user_id: rows[0].user_id, activity_type: rows[0].activity_type, start_time: rows[0].start_time, end_time: rows[0].end_time, source_device: rows[0].source_device, duration: rows[0].duration, duration_unit: rows[0].duration_unit, energy_burned: rows[0].energy_burned, statistics: rows.id filter ((row) -> row.stat_metric_type !=null ) map ((row) -> {
}) } ) --- point_metrics ++ sleep_sessions ++ workouts
